import{_ as t,o as r,c as a,a2 as o}from"./chunks/framework.BWuWLRhz.js";const u=JSON.parse('{"title":"🐧 Linux · Clash Verge Rev","description":"在 Linux 桌面发行版上使用 Clash Verge Rev 接入自由港机场。","frontmatter":{"description":"在 Linux 桌面发行版上使用 Clash Verge Rev 接入自由港机场。"},"headers":[],"relativePath":"clients/others/linux.md","filePath":"clients/others/linux.md","lastUpdated":1783252730000}'),d={name:"clients/others/linux.md"};function s(l,e,n,i,c,h){return r(),a("div",null,[...e[0]||(e[0]=[o('<h1 id="🐧-linux-·-clash-verge-rev" tabindex="-1">🐧 Linux · Clash Verge Rev <a class="header-anchor" href="#🐧-linux-·-clash-verge-rev" aria-label="Permalink to &quot;🐧 Linux · Clash Verge Rev&quot;">​</a></h1><blockquote><p><strong>与 Windows / macOS 同源的图形客户端</strong> | Ubuntu / Debian / Fedora / Arch 均可用</p></blockquote><p><a href="https://github.com/clash-verge-rev/clash-verge-rev" target="_blank" rel="noreferrer">Clash Verge Rev</a> 提供 Linux 桌面版本，界面与 Windows / macOS 版完全一致。</p><h2 id="📥-下载安装" tabindex="-1">📥 下载安装 <a class="header-anchor" href="#📥-下载安装" aria-label="Permalink to &quot;📥 下载安装&quot;">​</a></h2><p>前往 <a href="https://github.com/clash-verge-rev/clash-verge-rev/releases" target="_blank" rel="noreferrer">GitHub Releases</a> 下载对应格式：</p><table tabindex="0"><thead><tr><th>发行版</th><th>安装包</th><th>安装命令</th></tr></thead><tbody><tr><td>Ubuntu / Debian</td><td><code>.deb</code></td><td><code>sudo dpkg -i clash-verge_*.deb</code></td></tr><tr><td>Fedora / openSUSE</td><td><code>.rpm</code></td><td><code>sudo rpm -i clash-verge_*.rpm</code></td></tr><tr><td>Arch / Manjaro</td><td>AUR</td><td><code>yay -S clash-verge-rev-bin</code></td></tr><tr><td>通用</td><td><code>AppImage</code></td><td>赋予执行权限后直接运行</td></tr></tbody></table><div class="info custom-block"><p class="custom-block-title">INFO</p><p>GitHub 访问缓慢时，可以在下载链接前加镜像前缀 <code>https://gh.xxooo.cf/</code>（与 Windows 教程中的镜像加速相同）。</p></div><h2 id="🚀-配置步骤" tabindex="-1">🚀 配置步骤 <a class="header-anchor" href="#🚀-配置步骤" aria-label="Permalink to &quot;🚀 配置步骤&quot;">​</a></h2><p>流程与桌面端一致：</p><ol><li>登录<a href="https://freedomport.cc/#/dashboard" target="_blank" rel="noreferrer">会员中心</a>复制订阅链接</li><li>打开 Clash Verge Rev → <strong>配置（Profiles）</strong> → 粘贴 URL 导入</li><li>切到 <strong>代理（Proxies）</strong> 选择节点</li><li>在 <strong>设置</strong> 中开启 <strong>系统代理</strong>（或 TUN 模式）</li></ol><p>详细截图参考 <a href="./../windows/clash-verge">Windows 版教程</a>（界面一致）。</p><h2 id="❓-常见问题" tabindex="-1">❓ 常见问题 <a class="header-anchor" href="#❓-常见问题" aria-label="Permalink to &quot;❓ 常见问题&quot;">​</a></h2><p><strong>Q: 开启系统代理后终端不走代理？</strong> A: 终端需要单独设置环境变量：<code>export https_proxy=http://127.0.0.1:7897 http_proxy=http://127.0.0.1:7897</code>（端口以客户端设置为准），或开启 TUN 模式全局接管。</p><p><strong>Q: TUN 模式无法启动？</strong> A: 需要授予权限：设置中点击&quot;授权 TUN&quot;，或以 <code>sudo</code> 安装服务模式。</p>',14)])])}const g=t(d,[["render",s]]);export{u as __pageData,g as default};
